+  EXPECT_DOUBLE_EQ(seq.weighted_average(), 0.0);
+}
+
+TEST_VM(ShenandoahWeightedSeqTest, weighted_average_one_sample) {
+  ShenandoahWeightedSeq seq(SAMPLE_SIZE);
+  seq.add(1, 2, 2);
